import React from "react";

function Loginform() {
  return (
    <div style={{ padding: 20 }}>
      <h2>Login Page</h2>
      <input placeholder="Email" /><br /><br />
      <input type="password" placeholder="Password" /><br /><br />
      <button>Login</button>
    </div>
  );
}

export default Loginform;
